const body = $input.first().json.body || $input.first().json;

if (!body.entry || !body.entry[0]) {
  return [{ json: { skip: true, reason: 'No entry in payload' } }];
}

const entry = body.entry[0];
const messaging = entry.messaging?.[0];

if (!messaging || !messaging.message) {
  return [{ json: { skip: true, reason: 'No message in payload' } }];
}

const message = messaging.message;
const senderId = messaging.sender?.id; 
const recipientId = messaging.recipient?.id; 
const msgId = message.mid || message.item_id;
const timestamp = messaging.timestamp; 
const text = message.text || '';
const attachments = message.attachments;

let content = text;
let type = 'text';
let mediaUrl = null;

if (attachments && attachments.length > 0) {
  type = attachments[0].type; 
  mediaUrl = attachments[0].payload?.url;
  if (!content) {
    if (type === 'image') content = '[Imagem]';
    else if (type === 'video') content = '[Vídeo]';
    else if (type === 'audio') content = '[Áudio]';
    else content = '[Mídia]';
  }
}

return [{
  json: JSON.parse(JSON.stringify({
    whatsapp_msg_id: msgId || null,
    phone: senderId || null,
    contact_name: "IG User " + senderId, 
    direction: 'in',
    content: content || null,
    content_type: type || null,
    media_url: mediaUrl || null,
    timestamp: timestamp ? new Date(parseInt(timestamp)).toISOString() : null,
    raw_payload: body,
    source: "instagram"
  }))
}];

const settings = $('Fetch AI Settings').first()?.json;
if (!settings) {
  return [{ json: { run_ai: false, reason: 'No settings found' } }];
}

// Retrieve contact tags
let contact = {};
try {
  contact = $('Upsert Contact').first().json;
} catch(e) {
  try {
    contact = $input.first().json; // fallback
  } catch(err) {}
}

const tags = contact.tags || [];
const isPausedByTag = tags.includes('IA Inativa');

// Read columns directly from Supabase settings row
const isEnabledGlobal = settings.is_enabled === true;
const systemPrompt = settings.system_prompt || '';
const negativePrompt = settings.negative_prompt || '';
const apiKey = settings.api_key || '';
const model = settings.model || 'gpt-4o-mini';
const temperature = settings.temperature ?? 0.7;

// Find message info dynamically
let msgText = '';
let direction = 'in';
let phone = contact.phone || '';

try {
  const parsed = $('Parse Instagram').first().json;
  msgText = parsed.content || '';
  direction = parsed.direction || 'in';
  if (!phone) phone = parsed.phone || '';
} catch(e) {}

const isInbound = direction === 'in';

// Check pause trigger phrases
const pausePhrases = settings.pause_trigger_phrases || [];
const matchedPhrase = pausePhrases.find(p => msgText.toLowerCase().includes(p.toLowerCase()));

let pauseBot = false;
let runAi = false;
let reason = '';

if (!isEnabledGlobal) {
  reason = 'AI is disabled globally';
} else if (!isInbound) {
  reason = 'Message is outbound';
} else if (isPausedByTag) {
  reason = 'AI is paused for this contact (IA Inativa tag present)';
} else if (matchedPhrase) {
  pauseBot = true;
  reason = `AI paused by trigger phrase: "${matchedPhrase}"`;
} else {
  runAi = true;
  reason = 'All checks passed, running AI';
}

const updatedTags = isPausedByTag ? tags : [...tags, 'IA Inativa'];

return [{
  json: {
    run_ai: runAi,
    pause_bot: pauseBot,
    reason: reason,
    contact_id: contact.id,
    phone: phone,
    user_message: msgText,
    system_prompt: systemPrompt,
    negative_prompt: negativePrompt,
    api_key: apiKey,
    model: model,
    temperature: temperature,
    updated_tags: updatedTags
  }
}];

const msgs = $input.all().map(item => item.json);
const inboundMsgs = msgs.filter(m => m.direction === 'in');
const routerData = $('AI Routing Decision').first().json;
const welcomeMessage = routerData.welcome_message || '';

if (inboundMsgs.length <= 1 && welcomeMessage.trim() !== '') {
  return [{
    json: {
      is_welcome: true,
      contact_id: routerData.contact_id,
      phone: routerData.phone,
      channel_id: routerData.channel_id,
      content: welcomeMessage
    }
  }];
}

msgs.reverse();

const historyText = msgs.map(m => {
  const role = m.direction === 'in' ? 'USER' : 'ASSISTANT';
  return `${role}: ${m.content || ''}`;
}).join('\n\n');

const systemContent = `${routerData.system_prompt}\n\nRESTRISÇÕES IMPORTANTES (O QUE NUNCA FAZER):\n${routerData.negative_prompt}`;

const systemMessage = `${systemContent}\n\nCONVERSATION HISTORY:\n${historyText}`;

return [{
  json: {
    is_welcome: false,
    api_key: routerData.api_key,
    model: routerData.model,
    temperature: routerData.temperature,
    chatInput: routerData.user_message,
    systemMessage: systemMessage,
    contact_id: routerData.contact_id,
    phone: routerData.phone,
    channel_id: routerData.channel_id
  }
}];

const resp = $input.first().json;
const answer = resp.output || resp.text || resp.content || JSON.stringify(resp);
const inputData = $('Format Prompt & History').first().json;
return [{
  json: {
    contact_id: inputData.contact_id,
    phone: inputData.phone,
    channel_id: inputData.channel_id,
    content: answer
  }
}];

